    public class CustomX509CertificateValidator : X509CertificateValidator
    {
        public override void Validate(X509Certificate2 certificate)
        {
            if (certificate == null)
            {
                throw new ArgumentNullException("certificate");
            }

            if (DateTime.Now < certificate.NotBefore || DateTime.Now > certificate.NotAfter)
            {
                throw new SecurityTokenValidationException("Certificate is not valid for current date");
            }

            X509Chain chain = new X509Chain();
            chain.ChainPolicy.RevocationMode = X509RevocationMode.Online;
            chain.ChainPolicy.RevocationFlag = X509RevocationFlag.ExcludeRoot;
            chain.ChainPolicy.VerificationFlags = X509VerificationFlags.NoFlag;
            chain.ChainPolicy.VerificationTime = DateTime.Now;
            chain.ChainPolicy.UrlRetrievalTimeout = new TimeSpan(0, 0, 30);

            bool chainIsValid = chain.Build(certificate);

            if (!chainIsValid)
            {
                throw new SecurityTokenValidationException("Certificate chain validation failed");
            }
        }
    }

